class Solution:
    def maxStrength(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        max_strength = float('-inf')

        # Try all non-empty subsets
        for mask in range(1, 1 << n):
            product = 1
            for i in range(n):
                if mask & (1 << i):
                    product *= nums[i]
            max_strength = max(max_strength, product)

        return max_strength
